// build-market-intelligence — Validate and Extract Signals
// Validates required upstream inputs and extracts market signals for LLM prompt.
//
// CLOUD MODE: all data arrives via n8n item pipeline from orchestrator.
//             shopify_import is passed inline (no disk read).
// SELF-HOSTED: same pipeline. shopify_import may be absent if catalog context
//              was not forwarded — the workflow degrades gracefully.
//
// Catalog context (shopify_import) is optional.
// If absent, market_subcategories will be omitted from synthesis.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const storeProfile = input.store_profile;
const intakePayload = input.normalized_intake_payload;
const shopifyImport = input.shopify_import || null; // optional
const runtimeConfig = input.runtime_config;
const projectId = input.project_id;

// Propagate cloud_mode from upstream if set
if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) {
  cloudMode = true;
}

// Required inputs
if (!storeProfile || !storeProfile.store_id) {
  throw new Error('MISSING_ARTIFACT: store_profile with store_id is required. Run build-store-profile first.');
}
if (!intakePayload) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload is required. Run intake-store-input first.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

// Required store_profile fields
const profileRequired = ['store_id', 'vertical', 'price_positioning', 'primary_market', 'store_type', 'catalog_type'];
const profileMissing = profileRequired.filter(f => !storeProfile[f]);
if (profileMissing.length > 0) {
  throw new Error(`MISSING_ARTIFACT: store_profile missing required fields: ${profileMissing.join(', ')}`);
}

// Catalog context — optional
const rawProducts = (shopifyImport && shopifyImport.raw_products) ? shopifyImport.raw_products : [];
const rawCollections = (shopifyImport && shopifyImport.raw_collections) ? shopifyImport.raw_collections : [];
const hasCatalogContext = rawProducts.length > 0 || rawCollections.length > 0;

if (!hasCatalogContext) {
  console.warn(
    'CATALOG_CONTEXT_UNAVAILABLE: No Shopify product/collection data found in input. ' +
    'Falling back to vertical-only synthesis. market_subcategories will be omitted.'
  );
}

// Extract and deduplicate catalog signals (bounded to keep prompt lean)
const catalogContext = hasCatalogContext ? {
  product_types: [...new Set(rawProducts.map(p => p.product_type).filter(Boolean))].slice(0, 10),
  collection_titles: [...new Set(rawCollections.map(c => c.title).filter(Boolean))].slice(0, 10),
  vendor_names: [...new Set(rawProducts.map(p => p.vendor).filter(Boolean))].slice(0, 10),
} : null;

const marketSignals = {
  // From store_profile
  store_id: storeProfile.store_id,
  store_name: storeProfile.store_name || storeProfile.store_id,
  store_type: storeProfile.store_type,
  vertical: storeProfile.vertical,
  price_positioning: storeProfile.price_positioning,
  primary_market: storeProfile.primary_market,
  target_markets: storeProfile.target_markets || [storeProfile.primary_market],
  primary_language: storeProfile.primary_language || 'en',
  catalog_type: storeProfile.catalog_type,
  brand_maturity: storeProfile.brand_maturity || 'new',
  business_model: storeProfile.business_model || 'ecommerce',
  // From intake
  competitor_urls: intakePayload.competitor_urls || [],
  seo_goal: intakePayload.seo_goal || null,
  aeo_goal: intakePayload.aeo_goal || null,
  knowledge_content_priority: intakePayload.knowledge_content_priority || null,
  faq_intensity: intakePayload.faq_intensity || null,
  special_notes: intakePayload.special_notes || null,
  // Catalog context
  catalog_context: catalogContext,
  has_catalog_context: hasCatalogContext,
};

return [{
  json: {
    project_id: projectId,
    runtime_config: runtimeConfig,
    store_profile: storeProfile,
    market_signals: marketSignals,
    has_catalog_context: hasCatalogContext,
    cloud_mode: cloudMode,
  },
}];

// build-market-intelligence — Build LLM Prompt
// Assembles the structured prompt for market intelligence synthesis.
// Evidence boundary: internal signals only — no external market research.

const input = $input.first().json;
const signals = input.market_signals;
const hasCatalog = input.has_catalog_context;

// Determine which optional fields to request
const optionalFields = [];
if (signals.knowledge_content_priority && signals.knowledge_content_priority !== 'none') {
  optionalFields.push('content_opportunities');
}
if (signals.seo_goal) {
  optionalFields.push('seo_considerations');
}
if (signals.aeo_goal) {
  optionalFields.push('aeo_considerations');
}

const catalogLines = hasCatalog ? [
  'CATALOG CONTEXT (use as evidence for market subcategories):',
  '- Product types: ' + (signals.catalog_context.product_types.join(', ') || 'none'),
  '- Collection titles: ' + (signals.catalog_context.collection_titles.join(', ') || 'none'),
  '- Vendor names: ' + (signals.catalog_context.vendor_names.join(', ') || 'none'),
].join('\n') : 'CATALOG CONTEXT: Not available. Do NOT include market_subcategories in output.';

const competitorLine = (signals.competitor_urls && signals.competitor_urls.length > 0)
  ? 'COMPETITOR URL HINTS (for archetype labeling only — do not crawl): ' + signals.competitor_urls.join(', ')
  : 'COMPETITOR URLS: None provided. Classify competitor archetypes from vertical context only.';

const optionalSection = optionalFields.length > 0
  ? 'OPTIONAL FIELDS TO INCLUDE IN OUTPUT: ' + optionalFields.join(', ')
  : 'OPTIONAL FIELDS: Omit content_opportunities, seo_considerations, aeo_considerations.';

const synthesisNote = [
  'SYNTHESIS-ONLY: Generated by LLM from internal store signals on ' + new Date().toISOString() + '.',
  'Not validated against external market research.',
  'Treat all values as planning hypotheses requiring human review.',
  'Signals: vertical=' + signals.vertical + ', market=' + signals.primary_market + ', price_tier=' + signals.price_positioning + '.',
].join(' ');

const schemaLines = [
  '{',
  '  "market_category": "human-readable market category expanded from the vertical",',
  hasCatalog ? '  "market_subcategories": ["subcategory strings inferred from product types and collection titles"],' : '',
  '  "audience_segments": [{"segment_name": "string", "description": "string", "purchase_drivers": ["string"], "barriers": ["string"]}],',
  '  "core_problems": ["string — problems this product category solves"],',
  '  "purchase_motivators": ["string — key motivators in this vertical and price tier"],',
  '  "search_intents": [{"intent_type": "informational|commercial|transactional|navigational|comparison", "description": "string", "example_queries": ["string"]}],',
  '  "trust_factors": ["string — trust signals for this vertical and price positioning"],',
  '  "competitor_types": [{"type_name": "string", "description": "string", "strengths": ["string"], "weaknesses": ["string"]}],',
  '  "positioning_goals": ["string — strategic positioning objectives for this store"],',
  optionalFields.includes('content_opportunities') ? '  "content_opportunities": ["string"],' : '',
  optionalFields.includes('seo_considerations') ? '  "seo_considerations": ["string"],' : '',
  optionalFields.includes('aeo_considerations') ? '  "aeo_considerations": ["string"],' : '',
  '  "notes": "' + synthesisNote + '"',
  '}',
].filter(l => l !== '').join('\n');

const llmPrompt = [
  'You are a market intelligence analyst for an e-commerce store.',
  'Synthesize structured market intelligence exclusively from the internal store signals provided below.',
  '',
  'CONSTRAINTS:',
  '- Do NOT invent statistics, market share figures, search volumes, or demographic data.',
  '- All outputs are planning hypotheses — do not claim research certainty.',
  '- search_intents[*].intent_type must be one of: informational, commercial, transactional, navigational, comparison',
  '- Output valid JSON only. No markdown fences. No explanation outside the JSON object.',
  '',
  'STORE SIGNALS:',
  '- Vertical: ' + signals.vertical,
  '- Store type: ' + signals.store_type,
  '- Price positioning: ' + signals.price_positioning,
  '- Business model: ' + signals.business_model,
  '- Brand maturity: ' + signals.brand_maturity,
  '- Primary market: ' + signals.primary_market,
  '- Target markets: ' + (signals.target_markets || []).join(', '),
  '- SEO goal: ' + (signals.seo_goal || 'not specified'),
  '- AEO goal: ' + (signals.aeo_goal || 'not specified'),
  '- FAQ intensity: ' + (signals.faq_intensity || 'not specified'),
  '- Special notes: ' + (signals.special_notes || 'none'),
  '',
  catalogLines,
  '',
  competitorLine,
  '',
  optionalSection,
  '',
  'OUTPUT JSON SCHEMA (produce exactly this structure, populated with synthesized values):',
  schemaLines,
].join('\n');

return [{
  json: {
    project_id: input.project_id,
    runtime_config: input.runtime_config,
    store_profile: input.store_profile,
    market_signals: signals,
    has_catalog_context: hasCatalog,
    cloud_mode: input.cloud_mode,
    optional_fields: optionalFields,
    llm_prompt: llmPrompt,
  },
}];

// build-market-intelligence — Parse, Normalize, and Write
// Parses the LLM response, validates structure, and writes the artifact.
//
// CLOUD MODE: AJV validation and filesystem write are skipped.
//             market_intelligence is returned inline in output.
// SELF-HOSTED: Validates against schemas/market-intelligence.schema.json via AJV.
//              Writes atomically to projects/{project_id}/market-intelligence.json.
//              Updates checkpoint.json if present. Quarantines on schema failure.

let fs, path;
let cloudMode = false;
try {
  fs = require('fs');
  path = require('path');
} catch (_e) {
  cloudMode = true;
}

// LLM response from OpenAI node
const llmOutput = $input.first().json;

// Upstream context from Build LLM Prompt node
const upstream = $node['Build LLM Prompt'].json;

// Propagate cloud_mode from upstream
if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId = upstream.project_id;
const runtimeConfig = upstream.runtime_config;
const storeProfile = upstream.store_profile;
const optionalFields = upstream.optional_fields || [];
const hasCatalogContext = upstream.has_catalog_context || false;

// Extract text from OpenAI node output (simplifyOutput: true → message.content)
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

// Parse LLM response
let marketIntelligence;
try {
  let cleaned = rawText.trim();
  // Strip markdown code fences if present
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  marketIntelligence = JSON.parse(cleaned);
} catch (err) {
  throw new Error(
    'PARSE_ERROR: Failed to parse LLM response as JSON: ' + err.message +
    '. Raw response (first 500 chars): ' + String(rawText).slice(0, 500)
  );
}

// Validate required fields
if (!marketIntelligence.market_category) {
  throw new Error('MISSING_FIELD: LLM response missing required field: market_category.');
}

const requiredArrayFields = ['audience_segments', 'core_problems', 'purchase_motivators', 'search_intents', 'trust_factors', 'competitor_types', 'positioning_goals'];
for (const field of requiredArrayFields) {
  if (!marketIntelligence[field]) {
    throw new Error('MISSING_FIELD: LLM response missing required field: ' + field);
  }
  if (!Array.isArray(marketIntelligence[field]) || marketIntelligence[field].length === 0) {
    throw new Error('INVALID_FIELD: ' + field + ' must be a non-empty array. Got: ' + JSON.stringify(marketIntelligence[field]));
  }
}

// Validate search_intents enum
const validIntentTypes = ['informational', 'commercial', 'transactional', 'navigational', 'comparison'];
for (const intent of marketIntelligence.search_intents) {
  if (!validIntentTypes.includes(intent.intent_type)) {
    throw new Error(
      'SCHEMA_VIOLATION: search_intents[].intent_type "' + intent.intent_type + '" is not valid. ' +
      'Must be one of: ' + validIntentTypes.join(', ')
    );
  }
}

// Validate audience_segments structure
for (const seg of marketIntelligence.audience_segments) {
  if (!seg.segment_name || !seg.description) {
    throw new Error('SCHEMA_VIOLATION: Each audience_segment must have segment_name and description.');
  }
  if (!seg.purchase_drivers || !Array.isArray(seg.purchase_drivers) || seg.purchase_drivers.length === 0) {
    throw new Error('SCHEMA_VIOLATION: Each audience_segment must have purchase_drivers (non-empty array).');
  }
}

// Validate competitor_types structure
for (const ct of marketIntelligence.competitor_types) {
  if (!ct.type_name || !ct.description) {
    throw new Error('SCHEMA_VIOLATION: Each competitor_type must have type_name and description.');
  }
}

// Remove market_subcategories if catalog context was unavailable
if (!hasCatalogContext && marketIntelligence.market_subcategories) {
  console.warn('CATALOG_CONTEXT_UNAVAILABLE: Removing market_subcategories — no catalog context was available.');
  delete marketIntelligence.market_subcategories;
}

// Remove optional fields if they were not requested
for (const f of ['content_opportunities', 'seo_considerations', 'aeo_considerations']) {
  if (!optionalFields.includes(f) && marketIntelligence[f]) {
    delete marketIntelligence[f];
  }
}

// Ensure notes field has synthesis label
if (!marketIntelligence.notes || !marketIntelligence.notes.includes('SYNTHESIS-ONLY')) {
  marketIntelligence.notes = [
    'SYNTHESIS-ONLY: This artifact was generated by LLM synthesis from internal store signals.',
    'It has not been validated against external market research.',
    'Treat all values as planning hypotheses requiring human review.',
    'Generated: ' + new Date().toISOString() + '.',
    'Signals: vertical=' + storeProfile.vertical + ', market=' + storeProfile.primary_market + ', price_tier=' + storeProfile.price_positioning + '.',
  ].join(' ');
}

if (cloudMode) {
  // CLOUD SKIP: No AJV schema validation. No filesystem write.
  console.warn(
    'CLOUD_MODE: build-market-intelligence skipping AJV validation and artifact write for project: ' + projectId + '. ' +
    'market_intelligence returned inline.'
  );
  return [{
    json: {
      project_id: projectId,
      artifact_name: 'market-intelligence',
      artifact_path: null,
      market_intelligence: marketIntelligence,
      runtime_config: runtimeConfig,
      status: 'SUCCESS',
      cloud_mode: true,
      cloud_warnings: [
        'AJV schema validation skipped — no schema files accessible in n8n Cloud',
        'Artifact write skipped — no filesystem in n8n Cloud',
        'Checkpoint update skipped — no filesystem in n8n Cloud',
      ],
      notes: [
        !hasCatalogContext ? 'WARNING: No catalog context available. Synthesis based on vertical signals only. market_subcategories omitted.' : null,
      ].filter(Boolean),
    },
  }];
}

// SELF-HOSTED: AJV schema validation
const schemaPath = path.join(runtimeConfig.ajv_schema_path, 'market-intelligence.schema.json');
if (!fs.existsSync(schemaPath)) {
  throw new Error('SCHEMA_LOAD_ERROR: market-intelligence.schema.json not found at ' + schemaPath);
}
const schema = JSON.parse(fs.readFileSync(schemaPath, 'utf8'));

let AjvClass;
try {
  AjvClass = require('ajv/dist/2020');
} catch {
  try { AjvClass = require('ajv'); } catch (err) {
    throw new Error('SCHEMA_LOAD_ERROR: AJV not available: ' + err.message);
  }
}

const ajv = new AjvClass({ allErrors: true, strict: false });
const validate = ajv.compile(schema);
const valid = validate(marketIntelligence);

if (!valid) {
  const quarantineDir = path.join(runtimeConfig.project_root, projectId, '.runtime', 'quarantine');
  fs.mkdirSync(quarantineDir, { recursive: true });
  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  const quarantinePath = path.join(quarantineDir, 'market-intelligence.' + ts + '.rejected.json');
  fs.writeFileSync(quarantinePath, JSON.stringify({
    quarantine_reason: 'SCHEMA_VIOLATION',
    artifact_name: 'market-intelligence',
    workflow_id: 'build-market-intelligence',
    validation_errors: validate.errors,
    timestamp: new Date().toISOString(),
    project_id: projectId,
    artifact_payload: marketIntelligence,
  }, null, 2), 'utf8');
  const errorSummary = (validate.errors || []).map(e => (e.instancePath || '(root)') + ' ' + e.message).join('; ');
  throw new Error(
    'SCHEMA_VIOLATION: market-intelligence failed validation. Quarantined to ' + quarantinePath + '. Errors: ' + errorSummary
  );
}

// Atomic write
const projectDir = path.join(runtimeConfig.project_root, projectId);
const finalPath = path.join(projectDir, 'market-intelligence.json');
const tmpPath = path.join(projectDir, 'market-intelligence.tmp.json');
fs.mkdirSync(projectDir, { recursive: true });
fs.writeFileSync(tmpPath, JSON.stringify(marketIntelligence, null, 2), 'utf8');
fs.renameSync(tmpPath, finalPath);

// Update checkpoint
const checkpointPath = path.join(runtimeConfig.project_root, projectId, '.runtime', 'checkpoint.json');
const now = new Date().toISOString();
try {
  const checkpoint = JSON.parse(fs.readFileSync(checkpointPath, 'utf8'));
  checkpoint.completed_workflows.push({
    workflow_id: 'build-market-intelligence',
    completed_at: now,
    output_artifact: 'market-intelligence.json',
    status: 'SUCCESS',
  });
  checkpoint.last_updated_timestamp = now;
  checkpoint.next_workflow = 'build-brand-positioning';
  const cpTmp = checkpointPath + '.tmp';
  fs.writeFileSync(cpTmp, JSON.stringify(checkpoint, null, 2), 'utf8');
  fs.renameSync(cpTmp, checkpointPath);
} catch { /* non-fatal */ }

return [{
  json: {
    project_id: projectId,
    artifact_name: 'market-intelligence',
    artifact_path: finalPath,
    market_intelligence: marketIntelligence,
    runtime_config: runtimeConfig,
    status: 'SUCCESS',
    notes: [
      !hasCatalogContext ? 'WARNING: No catalog context available. Synthesis based on vertical signals only.' : null,
    ].filter(Boolean),
  },
}];
